/**
 * Returns true if the navigator's userAgent string or any userAgentData brand matches the given
 * regular expression.
 */
export function testUserAgent(re) {
    if (window.navigator == null)
        return false;
    return (window.navigator["userAgentData"]?.brands.some((brand) => re.test(brand.brand)) ||
        re.test(window.navigator.userAgent));
}
